values
('business:2-3-market-segmentation:match:ecdea777', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Income segmentation”?", "options": ["Dividing the market based on customers'' hobbies, interests and ways of living — e.g. sportswear for cyclists, specialist watches for divers", "The group of customers at which a product or service is aimed or targeted", "Dividing the market based on how much customers earn — e.g. luxury watches for the wealthy, budget watches for lower earners", "The splitting of the market for a product or service into different parts, or segments"]}'::jsonb, '{"answer": 2, "explain": "“Income segmentation” means: Dividing the market based on how much customers earn — e.g. luxury watches for the wealthy, budget watches for lower earners"}'::jsonb),
('business:2-3-market-segmentation:match:ec7351a8', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Location segmentation”?", "options": ["Allows a business to target advertising more accurately at the specific group most likely to buy the product, avoiding wasted spend", "Dividing the market based on where customers live — e.g. city vs. countryside, local vs. national", "Dividing the market based on how much customers earn — e.g. luxury watches for the wealthy, budget watches for lower earners", "The splitting of the market for a product or service into different parts, or segments"]}'::jsonb, '{"answer": 1, "explain": "“Location segmentation” means: Dividing the market based on where customers live — e.g. city vs. countryside, local vs. national"}'::jsonb),
('business:2-3-market-segmentation:match:6a58781c', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Lifestyle segmentation”?", "options": ["The group of customers at which a product or service is aimed or targeted", "Dividing the market based on whether customers are male or female — e.g. different clothing ranges for men and women", "Dividing the market based on customers'' hobbies, interests and ways of living — e.g. sportswear for cyclists, specialist watches for divers", "Dividing the market based on where customers live — e.g. city vs. countryside, local vs. national"]}'::jsonb, '{"answer": 2, "explain": "“Lifestyle segmentation” means: Dividing the market based on customers'' hobbies, interests and ways of living — e.g. sportswear for cyclists, specialist watches for divers"}'::jsonb),
('business:2-3-market-segmentation:match:b4f3437d', 'business', 'business:2-3-market-segmentation', '2.3 Market Segmentation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Benefit of segmentation (advertising)”?", "options": ["Allows a business to target advertising more accurately at the specific group most likely to buy the product, avoiding wasted spend", "The splitting of the market for a product or service into different parts, or segments", "Dividing the market based on how much customers earn — e.g. luxury watches for the wealthy, budget watches for lower earners", "Dividing the market based on how old customers are — e.g. targeting teenagers, over-50s, or families with young children"]}'::jsonb, '{"answer": 0, "explain": "“Benefit of segmentation (advertising)” means: Allows a business to target advertising more accurately at the specific group most likely to buy the product, avoiding wasted spend"}'::jsonb),
('business:2-4-1-introduction-marking-mix:exam:61d9a8ac', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'exam', 'mcq', 1, '{"num": "Q1", "question": "A business is deciding on a marketing mix for its latest product. The product is innovative, of the highest quality, and expensive to produce. The marketing mix for this business is most likely to also include:", "options": ["advertising aimed at low income customers", "placing the product for sale in high income locations", "promotion using free samples", "using social media to discuss the limitations of the product"], "hint": "Think about how the 4 Ps work together. If the ''Product'' is high quality and expensive, what must the ''Place'' be?", "starter": "An expensive, premium product needs to be sold somewhere that..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B</strong></p><p>This tests the student''s ability to see how ''Product'' directly influences ''Place'' and target market. A premium product requires a premium location.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-4-1-introduction-marking-mix:mcq:ed32337f', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'mcq', 'mcq', 1, '{"question": "What is one of the ''four Ps'' of the marketing mix?", "options": ["Penetration", "Place", "Planning", "Profit"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: The four Ps are Product, Price, Place, and Promotion. ''Penetration'' is a pricing strategy, not one of the main 4 Ps. ''Planning'' and ''Profit'' are general business terms."}'::jsonb),
('business:2-4-1-introduction-marking-mix:mcq:f4b83720', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'mcq', 'mcq', 1, '{"question": "An independent toy business is seeing fewer potential customers visit its shop. Which change to its marketing mix may help the business solve this problem?", "options": ["Introduce price skimming across the full range of toys", "Offer free superhero stickers and badges to all visitors", "Reduce the number of ''pre-school toy'' loss leaders offered", "Use digital distribution channels for outdoor toys"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Offering free stickers is a form of Promotion that acts as a draw to get footfall into the physical shop. Price skimming (A) would make toys more expensive, putting people off. Digital distribution (D) bypasses the shop entirely."}'::jsonb),
('business:2-4-1-introduction-marking-mix:mcq:3e72193f', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'mcq', 'mcq', 1, '{"question": "A furniture manufacturer''s marketing mix identifies:", "options": ["how to reduce risk when selling its furniture online", "the distribution channels for its tables and chairs", "the quantity of wood and materials to reorder", "which model of gaming chair customers prefer"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: This question tests the understanding of ''Place'' within the marketing mix, which specifically refers to distribution channels (how the product gets from the manufacturer to the consumer)."}'::jsonb),
('business:2-4-1-introduction-marking-mix:mcq:5d609a9a', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'mcq', 'mcq', 1, '{"question": "A publishing company''s marketing mix identifies:", "options": ["appropriate sources of market research", "digital distribution channels for its books", "how many short-story authors to interview", "which of its editors have training needs"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Similar to the furniture question, this targets the ''Place'' element of the marketing mix. Digital distribution is the modern ''Place'' for digital books and media."}'::jsonb),
('business:2-4-1-introduction-marking-mix:mcq:75159be1', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'mcq', 'mcq', 1, '{"question": "A business is deciding on a marketing mix for its latest product. The product is innovative, of the highest quality, and expensive to produce. The marketing mix is most likely to also include:", "options": ["advertising aimed at low income customers", "placing the product for sale in high income locations", "promotion using free samples", "using social media to discuss the limitations of the product"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: This tests how the 4 Ps work together. A premium, high-quality, expensive Product must be matched with an exclusive Place (high income locations) to reach the correct target market."}'::jsonb),
('business:2-4-1-introduction-marking-mix:tf:4543fec5', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'tf', 'tf', 1, '{"question": "The marketing mix consists of Planning, Product, Price, and Profit."}'::jsonb, '{"answer": false, "explain": "FALSE. The 4 Ps of the marketing mix are Product, Price, Place, and Promotion."}'::jsonb),
('business:2-4-1-introduction-marking-mix:tf:9813fa7d', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'tf', 'tf', 1, '{"question": "In the marketing mix, ''Place'' refers to the distribution channels used to get the product to the customer."}'::jsonb, '{"answer": true, "explain": "TRUE. ''Place'' is about distribution (like physical shops, websites, or wholesalers), not the location of the factory."}'::jsonb),
('business:2-4-1-introduction-marking-mix:tf:16c9282e', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'tf', 'tf', 1, '{"question": "A market-orientated business develops a product first and then tries to find customers to buy it."}'::jsonb, '{"answer": false, "explain": "FALSE. That describes a product-orientated business. A market-orientated business does market research first to find out what customers want before developing the product."}'::jsonb),
('business:2-4-1-introduction-marking-mix:tf:bf105c05', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'tf', 'tf', 1, '{"question": "If a business launches a highly premium, luxury product, it must ensure its Price, Place, and Promotion match that luxury image."}'::jsonb, '{"answer": true, "explain": "TRUE. The 4 Ps must be integrated and work together to avoid confusing the target market."}'::jsonb),
('business:2-4-1-introduction-marking-mix:learn:ca167ba4', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'learn', 'mcq', 1, '{"readingTitle": "What is the Marketing Mix?", "reading": "<p>The <strong>marketing mix</strong> is made up of different parts, often referred to as the <strong>4 Ps</strong>. These are:</p>\n      <ul>\n      <li><strong>Product:</strong> The good or service being sold (features, design, quality, packaging).</li>\n      <li><strong>Price:</strong> How much the customer pays for the product (pricing strategies).</li>\n      <li><strong>Place:</strong> How the product is distributed to the customer (shops, online, wholesalers).</li>\n      <li><strong>Promotion:</strong> How the business communicates with customers to encourage them to buy (advertising, special offers).</li>\n      </ul>\n      <p>A business must understand each one of these Ps and how they work together to help it successfully sell its products and services. The marketing mix is not a static plan; it must adapt and change as the market and consumer tastes change.</p>", "question": "Which four elements make up the marketing mix?", "options": ["Product, Price, Place, Promotion", "Product, Price, Planning, Profit", "Product, Positioning, Place, Promotion", "Packaging, Price, Place, Promotion"]}'::jsonb, '{"answer": 0, "explain": "The marketing mix is made up of the 4 Ps: Product, Price, Place, and Promotion."}'::jsonb),
('business:2-4-1-introduction-marking-mix:learn:db547181', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'learn', 'mcq', 1, '{"readingTitle": "Market-Orientated vs Product-Orientated", "reading": "<p>Before deciding on the 4 Ps, a business usually adopts one of two approaches:</p>\n      <p><strong>Market-orientated business:</strong> A business that bases its marketing mix entirely on sound market research. It finds out what the consumer wants <em>first</em>, and then designs a product to meet those needs. This approach is generally less risky.</p>\n      <p><strong>Product-orientated business:</strong> A business that focuses primarily on the creation and making of the product itself, rather than the needs of the market. They create a great product first and then try to find a market for it. This can be risky, but highly successful for innovative tech companies (e.g., the original Apple iPhone).</p>", "question": "Which approach involves a business researching what consumers want first, before designing the product?", "options": ["Sales-orientated", "Cost-orientated", "Product-orientated", "Market-orientated"]}'::jsonb, '{"answer": 3, "explain": "A market-orientated business bases its marketing mix on market research carried out before the product is designed, making it generally less risky."}'::jsonb),
('business:2-4-1-introduction-marking-mix:learn:df87ba96', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: The ''Big Four'' Supermarkets", "reading": "<p>The ''big four'' supermarkets (Tesco, Sainsbury’s, Asda, and Morrisons) are in close competition. Each needs the right marketing mix to persuade shoppers to visit them rather than rivals.</p>\n      <ul>\n      <li><strong>Price:</strong> Customers often want cheap prices. Supermarkets constantly watch competitors to ensure they aren''t being beaten on price, often price-matching basic items.</li>\n      <li><strong>Product:</strong> They offer a wide range of goods (food, clothing, electricals) and specific ranges like ''Taste the Difference'' (Sainsbury’s) to appeal to different segments. Budget rivals like Aldi/Lidl have a smaller range, reducing overheads.</li>\n      <li><strong>Place:</strong> Providing choice in <em>where</em> to shop. Tesco ''Metro'' and Sainsbury’s ''Local'' cater to town centres, while massive superstores sit on the outskirts. Home delivery offers another vital distribution channel.</li>\n      <li><strong>Promotion:</strong> Spending millions on advertising to tell customers about new offers and stay one step ahead of the competition.</li>\n      </ul>", "question": "In the supermarkets case study, Tesco ''Metro'' and Sainsbury''s ''Local'' stores catering to town centres, alongside outskirt superstores and home delivery, illustrate which element of the marketing mix?", "options": ["Promotion", "Place", "Product", "Price"]}'::jsonb, '{"answer": 1, "explain": "Offering different store formats and delivery options is about distribution channels, which is the ''Place'' element of the marketing mix."}'::jsonb),
('business:2-4-1-introduction-marking-mix:learn:ee8fc688', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'learn', 'mcq', 1, '{"readingTitle": "How the 4 Ps Work Together (Integration)", "reading": "<p>The 4 Ps cannot be planned in isolation; they are <strong>interdependent</strong>. If one changes, the others must often change to match it.</p>\n      <p>For example, if a business decides to create a highly innovative, premium quality item (<strong>Product</strong>), it will likely need to charge a high <strong>Price</strong> to cover expensive materials and portray a luxury image. It will need to distribute the item in high-end, exclusive locations (<strong>Place</strong>), and advertise in luxury magazines rather than cheap leaflets (<strong>Promotion</strong>).</p>\n      <p>If the mix is confused (e.g., a premium luxury product sold in a budget discount store), customers will be confused, and the product will likely fail.</p>", "question": "Why must the 4 Ps of the marketing mix be planned together rather than in isolation?", "options": ["Because customers only ever notice the Product and Price", "Because only Price and Promotion actually affect sales", "Because the law requires all four to be identical", "Because they are interdependent, changes affect the others"]}'::jsonb, '{"answer": 3, "explain": "The 4 Ps are interdependent — for example, a premium Product needs a high Price, exclusive Place, and upmarket Promotion to avoid confusing customers."}'::jsonb),
('business:2-4-1-introduction-marking-mix:misc:3004d6b4', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often think ''Place'' means the location where the product is manufactured (e.g., the factory).</p><p><strong>✅ The correct idea:</strong> ''Place'' refers specifically to DISTRIBUTION CHANNELS — how the product gets from the business to the consumer. This could be a physical retail shop, a wholesaler, or an e-commerce website.</p>", "question": "What does ''Place'' actually refer to in the marketing mix?", "options": ["The head office address of the business", "The location where the product is manufactured", "The design of the shop window display", "The distribution channels reaching the consumer"]}'::jsonb, '{"answer": 3, "explain": "''Place'' means distribution channels — e.g. a physical shop, a wholesaler, or a website — not the factory where the product is made."}'::jsonb),
('business:2-4-1-introduction-marking-mix:misc:6effe41f', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think the 4 Ps are chosen independently and don''t affect each other.</p><p><strong>✅ The correct idea:</strong> The 4 Ps are highly INTERDEPENDENT. If you change your product to make it more luxurious, you must also change your price (increase it), place (exclusive shops), and promotion (high-end magazines) to match.</p>", "question": "If a business makes its product more luxurious, what does the idea of an ''interdependent'' marketing mix suggest it should also do?", "options": ["Adjust price, place and promotion to match the new positioning", "Keep price, place and promotion exactly the same to save costs", "Only change promotion, since customers only respond to adverts", "Lower the price to attract more customers to the new product"]}'::jsonb, '{"answer": 0, "explain": "Because the 4 Ps are interdependent, making the product more luxurious means price, place and promotion must also change to match, e.g. a higher price and exclusive shops."}'::jsonb),
('business:2-4-1-introduction-marking-mix:misc:cb9c60ef', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students assume that a product-orientated business will always fail because they don''t do market research first.</p><p><strong>✅ The correct idea:</strong> While riskier, product-orientated businesses can be massively successful if they create a highly innovative product that consumers didn''t even know they wanted yet (e.g., the first smartphones or early tech inventions).</p>", "question": "Which statement about product-orientated businesses is most accurate?", "options": ["They are only ever used by budget supermarkets", "They always fail because they skip market research entirely", "They can never be profitable in the long term", "They can be highly successful with a truly innovative product"]}'::jsonb, '{"answer": 3, "explain": "Product-orientated businesses are riskier but can succeed spectacularly with highly innovative products, as seen with early smartphones."}'::jsonb),
('business:2-4-1-introduction-marking-mix:tips:77ad7022', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'tips', 'mcq', 1, '{"readingTitle": "Multiple Choice (1 mark) — Tricks with ''Place''", "reading": "<p>In multiple choice questions, examiners love testing your understanding of ''Place''.</p>\n      <p>Always remember: Place = <strong>Distribution Channels</strong>.</p>\n      <p>If you see options about factories, warehouses, or ordering raw materials, ignore them. Look for words like ''digital distribution'', ''retailers'', or ''wholesalers''.</p>", "question": "In a multiple-choice question about ''Place'', which type of answer option should you avoid selecting?", "options": ["Options describing retailers", "Options describing digital distribution channels such as websites", "Options describing wholesalers", "Options describing factories, warehouses or ordering raw materials"]}'::jsonb, '{"answer": 3, "explain": "Place = distribution channels, so factory, warehouse and raw-material options are distractors testing production, not distribution."}'::jsonb),
('business:2-4-1-introduction-marking-mix:tips:8a88fdf9', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'tips', 'mcq', 1, '{"readingTitle": "Concept Link — Linking the Mix to the Target Market", "reading": "<p>When devising a marketing mix, it must always link back to the <strong>target market</strong> (from Unit 2.3).</p>\n      <p>If an exam scenario says the target market is ''low-income teenagers'', every part of your suggested 4 Ps must match that demographic: low price, digital promotion (social media), modern design, and online/accessible place.</p>", "question": "If an exam case study describes the target market as ''low-income teenagers'', what should your suggested marketing mix include?", "options": ["A low price, digital promotion, and accessible place", "A high price and exclusive, luxury store locations", "Premium packaging with print magazine adverts only", "A focus on Price alone, ignoring the other three Ps"]}'::jsonb, '{"answer": 0, "explain": "Every part of the 4 Ps must link back to the target market, so ''low-income teenagers'' calls for low price, digital promotion, and accessible place."}'::jsonb),
('business:2-4-1-introduction-marking-mix:tips:ac474b3c', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (9 marks) — Creating a Marketing Mix", "reading": "<p>For high tariff questions, you may be asked to evaluate a proposed marketing mix or recommend one.</p>\n      <p>To score top marks, you must explicitly state how the parts of the mix <strong>work together</strong>. Don''t just list a price and a promotion separately. Explain <em>why</em> that specific price supports that specific promotion method.</p>", "question": "To achieve top marks in a high-tariff (9 mark) question evaluating a marketing mix, what must you explicitly do?", "options": ["Explain how the mix''s parts work together, not separately", "Describe the business''s history and background", "Focus only on describing the Product element in detail", "List as many possible prices and promotions as you can"]}'::jsonb, '{"answer": 0, "explain": "Top marks require explicitly explaining why a specific price supports a specific promotion, showing the mix works together rather than just listing the Ps separately."}'::jsonb),
('business:2-4-1-introduction-marking-mix:fib:fbe943f2', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'fib', 'fib', 2, '{"question": "The marketing mix is made up of four key parts, known as the 4 Ps: Product, _____, Place, and _____.", "blankOptions": {"B1": ["distribution", "high", "Price", "market"], "B2": ["product", "business", "advertising", "Promotion"]}}'::jsonb, '{"blanks": {"B1": "Price", "B2": "Promotion"}}'::jsonb),
('business:2-4-1-introduction-marking-mix:fib:377227e4', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'fib', 'fib', 2, '{"question": "A _____ orientated business relies heavily on market research, whereas a _____ orientated business focuses on the creation and design of the item itself.", "blankOptions": {"B1": ["customer", "Promotion", "Price", "market"], "B2": ["customer", "product", "sales", "Promotion"]}}'::jsonb, '{"blanks": {"B1": "market", "B2": "product"}}'::jsonb),
('business:2-4-1-introduction-marking-mix:fib:d31d7474', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'fib', 'fib', 2, '{"question": "In the marketing mix, ''Place'' does not just mean the physical shop; it refers to the _____ channels used to get the product to the _____.", "blankOptions": {"B1": ["distribution", "market", "high", "product"], "B2": ["business", "together", "market", "customer"]}}'::jsonb, '{"blanks": {"B1": "distribution", "B2": "customer"}}'::jsonb),
('business:2-4-1-introduction-marking-mix:fib:9a27abb0', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'fib', 'fib', 2, '{"question": "All elements of the marketing mix must work _____ to be successful. For example, a premium product should have a _____ price.", "blankOptions": {"B1": ["together", "business", "advertising", "sales"], "B2": ["business", "Price", "sales", "high"]}}'::jsonb, '{"blanks": {"B1": "together", "B2": "high"}}'::jsonb),
('business:2-4-1-introduction-marking-mix:match:33c2c01d', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Product”?", "options": ["Ensuring that all four parts of the marketing mix work together and send a consistent message to the consumer", "A business approach that focuses on creating a high-quality product first, and then trying to find a market for it", "The good or service that a business provides to meet a customer need", "The amount of money that a customer must pay to acquire the good or service"]}'::jsonb, '{"answer": 2, "explain": "“Product” means: The good or service that a business provides to meet a customer need"}'::jsonb),
('business:2-4-1-introduction-marking-mix:match:fed2683e', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price”?", "options": ["The amount of money that a customer must pay to acquire the good or service", "The methods used to communicate with customers and persuade them to buy", "Ensuring that all four parts of the marketing mix work together and send a consistent message to the consumer", "A business approach that focuses on finding out what the consumer wants through research before designing the product"]}'::jsonb, '{"answer": 0, "explain": "“Price” means: The amount of money that a customer must pay to acquire the good or service"}'::jsonb),
('business:2-4-1-introduction-marking-mix:match:347b02aa', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Place”?", "options": ["A business approach that focuses on finding out what the consumer wants through research before designing the product", "The good or service that a business provides to meet a customer need", "The distribution channels used to get the product from the producer to the consumer", "The methods used to communicate with customers and persuade them to buy"]}'::jsonb, '{"answer": 2, "explain": "“Place” means: The distribution channels used to get the product from the producer to the consumer"}'::jsonb),
('business:2-4-1-introduction-marking-mix:match:58d9d52c', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Promotion”?", "options": ["The amount of money that a customer must pay to acquire the good or service", "A business approach that focuses on creating a high-quality product first, and then trying to find a market for it", "The methods used to communicate with customers and persuade them to buy", "The good or service that a business provides to meet a customer need"]}'::jsonb, '{"answer": 2, "explain": "“Promotion” means: The methods used to communicate with customers and persuade them to buy"}'::jsonb),
('business:2-4-1-introduction-marking-mix:match:ace7573a', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market-orientated”?", "options": ["A business approach that focuses on finding out what the consumer wants through research before designing the product", "The good or service that a business provides to meet a customer need", "Ensuring that all four parts of the marketing mix work together and send a consistent message to the consumer", "A business approach that focuses on creating a high-quality product first, and then trying to find a market for it"]}'::jsonb, '{"answer": 0, "explain": "“Market-orientated” means: A business approach that focuses on finding out what the consumer wants through research before designing the product"}'::jsonb),
('business:2-4-1-introduction-marking-mix:match:69c5a9fc', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Product-orientated”?", "options": ["Ensuring that all four parts of the marketing mix work together and send a consistent message to the consumer", "The methods used to communicate with customers and persuade them to buy", "A business approach that focuses on finding out what the consumer wants through research before designing the product", "A business approach that focuses on creating a high-quality product first, and then trying to find a market for it"]}'::jsonb, '{"answer": 3, "explain": "“Product-orientated” means: A business approach that focuses on creating a high-quality product first, and then trying to find a market for it"}'::jsonb),
('business:2-4-1-introduction-marking-mix:match:e9116ef1', 'business', 'business:2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Integrated mix”?", "options": ["Ensuring that all four parts of the marketing mix work together and send a consistent message to the consumer", "The methods used to communicate with customers and persuade them to buy", "The good or service that a business provides to meet a customer need", "The amount of money that a customer must pay to acquire the good or service"]}'::jsonb, '{"answer": 0, "explain": "“Integrated mix” means: Ensuring that all four parts of the marketing mix work together and send a consistent message to the consumer"}'::jsonb),
('business:2-4-2-product-and-product-life:mcq:6a24c675', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'mcq', 'mcq', 1, '{"question": "The second stage in the product life cycle is:", "options": ["Maturity", "Introduction", "Decline", "Growth"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: The four stages are Introduction, Growth, Maturity, and Decline. Therefore, Growth is the second stage."}'::jsonb),
('business:2-4-2-product-and-product-life:mcq:3fe66dee', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'mcq', 'mcq', 1, '{"question": "Product innovation is concerned with:", "options": ["changing the colour of a product", "developing new features in a product that have not been seen before", "selling the product at a lower price than competitors", "making sure a competitor does not copy your product"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Innovation is the improvement on an existing idea, often involving new processes or features that enhance the product."}'::jsonb),
('business:2-4-2-product-and-product-life:mcq:53ee6a66', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'mcq', 'mcq', 1, '{"question": "Which of the following would NOT be used to extend the product life cycle of a product?", "options": ["Bring out a new product", "Increase the advertising", "Decrease the price", "Offer additional features free of charge"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: Bringing out a completely new product replaces the old one; it does not extend the life cycle of the *existing* product. Options B, C, and D are all valid extension strategies."}'::jsonb),
('business:2-4-2-product-and-product-life:mcq:816ab620', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'mcq', 'mcq', 1, '{"question": "Innovation in a product is best described as:", "options": ["devising a better product by changing an existing product", "looking at a product and designing a completely new product", "designing and building a new technology product from scratch", "making sure your product is made as well as competitors'' products"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: Innovation means taking something that already exists and making it better. Designing from scratch is ''Invention''."}'::jsonb),
('business:2-4-2-product-and-product-life:mcq:dab2b56f', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'mcq', 'mcq', 1, '{"question": "Invention involves:", "options": ["behaving dishonestly", "creating new products", "developing existing products", "discrimination in the workplace"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Invention is the creation of a totally new product or service. Developing existing products is ''innovation''."}'::jsonb),
('business:2-4-2-product-and-product-life:mcq:236fbaba', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'mcq', 'mcq', 1, '{"question": "What is the final stage of the product life cycle?", "options": ["Decline", "Delegation", "Distribution", "Diversification"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: The final stage is Decline, where sales fall as customers switch to newer alternatives."}'::jsonb),
('business:2-4-2-product-and-product-life:mcq:75159be1', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'mcq', 'mcq', 1, '{"question": "A business is deciding on a marketing mix for its latest product. The product is innovative, of the highest quality, and expensive to produce. The marketing mix is most likely to also include:", "options": ["advertising aimed at low income customers", "placing the product for sale in high income locations", "promotion using free samples", "using social media to discuss the limitations of the product"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: A premium, innovative product must be matched with an exclusive ''Place'' (distribution channel) to reach the correct target market and justify the high price."}'::jsonb),
('business:2-4-2-product-and-product-life:tf:0ac200a4', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'tf', 'tf', 1, '{"question": "Innovation means inventing a completely new product from scratch."}'::jsonb, '{"answer": false, "explain": "FALSE. Invention is creating something from scratch. Innovation is improving an existing product."}'::jsonb),
('business:2-4-2-product-and-product-life:tf:90baedd5', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'tf', 'tf', 1, '{"question": "The product life cycle shows the sales of a product measured against time."}'::jsonb, '{"answer": true, "explain": "TRUE. The Y-axis is Sales and the X-axis is Time."}'::jsonb),
('business:2-4-2-product-and-product-life:tf:b6a84ff9', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'tf', 'tf', 1, '{"question": "A product at the maturity stage is experiencing its fastest rate of sales growth."}'::jsonb, '{"answer": false, "explain": "FALSE. The fastest rate of sales growth happens in the ''Growth'' stage. In Maturity, sales are at their highest total volume, but the *rate of growth* has slowed down and leveled off."}'::jsonb),
('business:2-4-2-product-and-product-life:tf:3bd5bbe9', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'tf', 'tf', 1, '{"question": "Decreasing the price of a product is a common extension strategy."}'::jsonb, '{"answer": true, "explain": "TRUE. Lowering the price can attract budget-conscious customers and help maintain sales, extending the maturity stage."}'::jsonb),
('business:2-4-2-product-and-product-life:tf:9848355b', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'tf', 'tf', 1, '{"question": "The product life cycle accurately predicts what competitors will do in the future."}'::jsonb, '{"answer": false, "explain": "FALSE. One of the main limitations of the PLC is that it ignores external factors, including competitor actions and changing social trends."}'::jsonb),
('business:2-4-2-product-and-product-life:learn:2ff45e11', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'learn', 'mcq', 1, '{"readingTitle": "The Importance of Product & Adding Value", "reading": "<p><strong>Product</strong> is a vital part of the marketing mix. A product is a good or a service that is sold to customers or other businesses to meet a need. Businesses will always try to supply products that customers will want to buy, at a price at which the business can make the required profit.</p>\n      <p>Businesses generally operate under one of two orientations:</p>\n      <ul>\n      <li><strong>Market Orientation:</strong> The business focuses on the market. It responds to customer needs and wants through market research before developing the product.</li>\n      <li><strong>Product Orientation:</strong> The business focuses on the products. It develops goods based on what it is good at doing, creating the product first and finding a market later.</li>\n      </ul>\n      <p><strong>Ways to Add Value to a Product or Service (Product Differentiation):</strong></p>\n      <p>To stand out from rivals, a business must differentiate its product. This can be done by:</p>\n      <ul>\n      <li><strong>Branding:</strong> Establishing a strong brand image.</li>\n      <li><strong>Design:</strong> Making the product look stylish or function better.</li>\n      <li><strong>Quality:</strong> Using better materials or offering superior durability.</li>\n      <li><strong>Selling Point:</strong> Making clear the Unique Selling Point (USP).</li>\n      <li><strong>Convenience:</strong> Offering a better location or easier usability than rival products.</li>\n      </ul>", "question": "A business that designs goods based on what it is good at making, then looks for a market afterwards, is showing which orientation?", "options": ["Product orientation", "Price orientation", "Market orientation", "Promotion orientation"]}'::jsonb, '{"answer": 0, "explain": "Product orientation means the business focuses on the product first, creating it before finding a market, unlike market orientation which starts with customer research."}'::jsonb),
('business:2-4-2-product-and-product-life:learn:4e9114c8', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'learn', 'mcq', 1, '{"readingTitle": "Invention, Design, and Innovation", "reading": "<p>Technology plays a massive role in product development. Businesses spend large sums of money on <strong>Research and Development (R&D)</strong> to stay ahead of the competition.</p>\n      <ul>\n      <li><strong>Invention:</strong> When a business comes up with a completely new product, service, or feature that has never existed before (e.g., the creation of the internet itself).</li>\n      <li><strong>Innovation:</strong> When a business improves on an existing product or idea, often using new processes or technology (e.g., developing internet banking from traditional banking).</li>\n      <li><strong>Design:</strong> When a business plans what a product will do (its function) and what it will look like (its style). Design is critical in markets like mobile phones and fashion.</li>\n      </ul>\n      <div class=\"case-study-box\">\n      <h4>Case Study: Dyson — From Vacuum to Strawberries</h4>\n      <p>When James Dyson became unhappy about the efficiency of bagged vacuum cleaners in the 1970s, he decided to do something about it. After spending a lot of time on invention, design and innovation, he came up with the Dual Cyclone style vacuum cleaner we are familiar with today. He built many different versions before it was ready to be sold.</p>\n      <p>The vacuum cleaner side of the business saw further innovation and design changes with the introduction of the Dyson ''Ball'' upright cleaner and cordless ranges. Not content with a narrow range, Dyson designed a new style of hand dryers, hair straighteners, and air purifiers. It even uses its technological know-how to grow strawberries at its Dyson Farming operation in Lincolnshire! Dyson is an excellent example of a business continually developing its product range to meet consumer needs.</p>\n      </div>", "question": "Dyson developing internet banking-style improvements to an already-existing product, such as upgrading a vacuum cleaner to a cordless version, is best described as:", "options": ["Innovation", "Invention", "Market orientation", "Extension pricing"]}'::jsonb, '{"answer": 0, "explain": "The card defines innovation as improving an existing product or idea using new processes or technology, whereas invention means creating something completely new that never existed before."}'::jsonb),
('business:2-4-2-product-and-product-life:learn:9f719ff9', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'learn', 'mcq', 1, '{"readingTitle": "Branding and Image", "reading": "<p><strong>Branding</strong> is closely linked to design and image. How a customer feels about owning a product is a powerful marketing tool (e.g., the prestige of owning an exclusive sports car).</p>\n      <p>Many companies do not even need to put their name on a product — we know the make simply by a symbol, known as a <strong>trade mark</strong> (e.g., the Nike swoosh or Apple logo). We understand from that symbol that this ''brand'' has a certain quality. It may be high quality or a lower quality ''budget'' standard, but the consumer knows exactly what to expect. This works well in fast food too; brand names like KFC or McDonald''s give customers a clear idea of the standard of product they are buying.</p>\n      <p><strong>Activity 7: Marketing Considerations</strong><br>\n      <em>When marketing a mobile phone vs a waste-paper bin, what is most important? Price, design, image, or brand?</em><br>\n      <strong>Answer:</strong> This is highly subjective. A waste-paper bin might compete primarily on price and basic design. However, a mobile phone relies heavily on brand and image (e.g., Apple vs Samsung), followed by innovative design. It highlights that a business must carefully choose which element of the mix to concentrate on based on the product type.</p>", "question": "A symbol such as the Nike swoosh, which lets customers recognise a make and its quality without the company name being shown, is known as a:", "options": ["Extension strategy", "Trade mark", "Market segment", "USP statement"]}'::jsonb, '{"answer": 1, "explain": "The card explains that a trade mark is a symbol customers associate with a brand''s quality, even without the company name appearing on the product."}'::jsonb),
('business:2-4-2-product-and-product-life:learn:6201c3bb', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'learn', 'mcq', 1, '{"readingTitle": "The Product Life Cycle (PLC)", "reading": "<p>Most products have a time span over which consumers will want them. This is called the <strong>product life cycle</strong>. It is shown as a graph mapping Sales against Time. The graph is split into four key stages:</p>\n      <ol>\n      <li><strong>Introduction:</strong> The product is new and just launched. Sales are just beginning. Advertising is usually very high to make customers aware of the product.</li>\n      <li><strong>Growth:</strong> Sales grow quickly as the product becomes well-known. There is no need for special offers because demand is high.</li>\n      <li><strong>Maturity:</strong> Sales reach their peak and level off. The rate of growth is slowing down. It may be necessary to support the product with further advertising and offers to maintain sales against competitors.</li>\n      <li><strong>Decline:</strong> Sales begin to fall. Customers see the product as old and switch to newer alternatives. A successful business should already have a replacement product ready.</li>\n      </ol>\n      <p><strong>Activity 10 & 11: Real World Life Cycles</strong><br>\n      <em>Desktop Computers:</em> Maturity/Decline (replaced by tablets/laptops).<br>\n      <em>Denim Jeans:</em> Maturity (they go on forever, only the cut changes).<br>\n      <em>iPhone 12:</em> Growth/Maturity (short life cycle, replaced quickly).<br>\n      <em>Chart Single:</em> Extremely short life cycle (peaks and declines in weeks).<br>\n      <em>Dairy Milk Bar:</em> Exceptionally long maturity stage spanning decades.</p>", "question": "During which stage of the Product Life Cycle is advertising usually at its highest, to make customers aware a product exists?", "options": ["Growth", "Maturity", "Introduction", "Decline"]}'::jsonb, '{"answer": 2, "explain": "The card states that in the Introduction stage the product is new and just launched, so advertising is usually very high to build awareness."}'::jsonb),
('business:2-4-2-product-and-product-life:learn:31460637', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'learn', 'mcq', 1, '{"readingTitle": "Extending the Product Life Cycle", "reading": "<p>The highest level of sales is at the end of growth and into maturity. Businesses try to keep sales at this high level for as long as possible using <strong>Extension Strategies</strong>:</p>\n      <ul>\n      <li><strong>Advertising:</strong> Claiming the product is \"new and improved\" or using modern packaging.</li>\n      <li><strong>Price Reductions:</strong> Lowering the price to make the product more attractive.</li>\n      <li><strong>New Markets:</strong> Exporting the product to countries where it is still in the ''introduction'' phase.</li>\n      <li><strong>New Features/Uses:</strong> Adding new flavours, features, or targeting a different demographic.</li>\n      </ul>\n      <div class=\"case-study-box\">\n      <h4>Activity 13: Rice Krispies Case Study</h4>\n      <p>Since it started in 1928, Kellogg’s Rice Krispies has been a breakfast favourite. It is currently in a very long <strong>Maturity</strong> stage. Kellogg''s extended its life cycle by developing the product to include new flavours (strawberry/banana) and creating new uses, such as Rice Krispies cereal bars for the ''on-the-go'' snack market. The Kellogg''s brand name was vital to this success, allowing them to sell different products based on a known, trusted formula.</p>\n      </div>", "question": "Kellogg''s creating Rice Krispies cereal bars for the ''on-the-go'' snack market, alongside its original cereal, is an example of which extension strategy?", "options": ["Price reduction", "New features/uses", "New markets", "Market orientation"]}'::jsonb, '{"answer": 1, "explain": "The card lists ''New Features/Uses'' as an extension strategy, and the Rice Krispies bars are given as the example of adding a new use to reach the snack market."}'::jsonb),
('business:2-4-2-product-and-product-life:learn:cad061a5', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'learn', 'mcq', 1, '{"readingTitle": "Uses and Limitations of the Product Life Cycle", "reading": "<div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Uses of the PLC</div>\n      <div class=\"pro-item\">Identifies exactly when to introduce <strong>extension strategies</strong> (e.g., right before decline).</div>\n      <div class=\"pro-item\">Helps a business know when to change its <strong>marketing spending</strong> (e.g., heavy advertising in Introduction, less in Growth).</div>\n      <div class=\"pro-item\">Identifies when a product should finally be <strong>discontinued</strong> or replaced.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Limitations of the PLC</div>\n      <div class=\"con-item\"><strong>Ignores Competitors:</strong> It doesn''t consider what rival businesses are doing, which can prematurely end a product''s life.</div>\n      <div class=\"con-item\"><strong>Unpredictable Trends:</strong> It cannot predict sudden shifts in social trends or changes in consumer taste.</div>\n      <div class=\"con-item\"><strong>Not a Guarantee:</strong> Past performance on a graph is not always a reliable indicator of future performance.</div>\n      </div>\n      </div>\n      <p><strong>Evaluation Point:</strong> It is very difficult for a business to judge the right time to replace a product. Car manufacturers face massive R&D costs to launch a new model (every 5-6 years), so they rely heavily on extending the life cycle. However, in fast-paced tech markets (phones, computers), businesses put much less effort into extension strategies and instead focus on constantly innovating the next replacement model.</p>", "question": "A key limitation of the Product Life Cycle model is that it:", "options": ["Always predicts decline within one year", "Cannot be shown as a graph", "Only applies to services, not goods", "Ignores what rival businesses are doing"]}'::jsonb, '{"answer": 3, "explain": "The card lists ''Ignores Competitors'' as a limitation, since the PLC doesn''t consider rival actions that can prematurely end a product''s life."}'::jsonb),
('business:2-4-2-product-and-product-life:misc:ee547fbe', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often confuse Invention and Innovation.</p><p><strong>✅ The correct idea:</strong> INVENTION is creating something totally new from scratch that didn''t exist before. INNOVATION is taking an existing product and making it better (e.g., adding a camera to a mobile phone).</p>", "question": "Adding a camera to an already-existing mobile phone is an example of which concept?", "options": ["Innovation", "Invention", "Market orientation", "Extension pricing"]}'::jsonb, '{"answer": 0, "explain": "Innovation means improving an existing product, unlike invention, which means creating something totally new from scratch."}'::jsonb),
('business:2-4-2-product-and-product-life:misc:46deba1a', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think the Product Life Cycle can perfectly predict the future.</p><p><strong>✅ The correct idea:</strong> The PLC is just a model based on past data. It cannot predict sudden changes in consumer tastes, sudden technological breakthroughs by competitors, or economic crashes. It is a guide, not a crystal ball.</p>", "question": "Why can the Product Life Cycle not be relied upon to perfectly predict a product''s future sales?", "options": ["It only applies to products sold internationally", "It is updated automatically by competitors'' data", "It is only a model based on past data", "It only measures profit, not sales"]}'::jsonb, '{"answer": 2, "explain": "The card explains the PLC is a guide based on past data, not a crystal ball, so it cannot predict sudden changes in tastes, competitor breakthroughs, or economic crashes."}'::jsonb),
('business:2-4-2-product-and-product-life:misc:8abfb88a', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think all products go through the decline stage quickly.</p><p><strong>✅ The correct idea:</strong> Some products stay in the Maturity stage for decades (e.g., Coca-Cola, Kellogg''s Cornflakes, Denim Jeans) because of excellent extension strategies and brand loyalty. Not everything declines rapidly like a smartphone.</p>", "question": "Products like Coca-Cola and Denim Jeans staying in the Maturity stage for decades shows that:", "options": ["Decline is impossible once a brand becomes well known", "All products follow an identical life cycle length", "Strong brands like these can extend maturity for decades", "Maturity always lasts exactly as long as Introduction"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception that all products decline quickly, showing that strong extension strategies and brand loyalty can keep products in maturity for decades."}'::jsonb),
('business:2-4-2-product-and-product-life:tips:5cc9735f', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'tips', 'mcq', 1, '{"readingTitle": "Multiple Choice (1 mark) — Reading PLC Graphs", "reading": "<p>Examiners frequently use graphs to test the Product Life Cycle.</p>\n      <ul>\n      <li>If the ''X'' is on the first small upward slope $\rightarrow$ <strong>Introduction</strong>.</li>\n      <li>If the ''X'' is on the steepest upward curve $\rightarrow$ <strong>Growth</strong>.</li>\n      <li>If the ''X'' is at the very top (the peak) or on a flat plateau $\rightarrow$ <strong>Maturity</strong>.</li>\n      <li>If the ''X'' is on the downward slope $\rightarrow$ <strong>Decline</strong>.</li>\n      </ul>", "question": "On a Product Life Cycle graph, if a marked point ''X'' sits on a flat plateau at the very top of the curve, which stage does it show?", "options": ["Introduction", "Growth", "Maturity", "Decline"]}'::jsonb, '{"answer": 2, "explain": "The exam tip states that an ''X'' at the peak or on a flat plateau of the graph represents the Maturity stage."}'::jsonb),
('business:2-4-2-product-and-product-life:tips:cfceaa9c', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (3 marks) — Analysing Extension Strategies", "reading": "<p>If asked to analyse how a business extended a product''s life cycle (e.g., Lego or Kellogg''s), follow the chain of reasoning:</p>\n      <p><strong>Identify the method</strong> (e.g., introducing new movie-themed characters) $\rightarrow$ <strong>Apply to the business</strong> (Lego Harry Potter sets) $\rightarrow$ <strong>Business Impact</strong> (Attracts a new target market, increasing sales revenue and reversing the decline).</p>", "question": "For a 3-mark ''analyse'' question on extending a product''s life cycle, what is the correct chain of reasoning to follow?", "options": ["List every extension strategy without applying any to the business", "Describe the product''s price only", "Identify the method, apply it to the business, then explain why", "State the definition, give one example, then stop"]}'::jsonb, '{"answer": 2, "explain": "The exam tip sets out the chain: identify the method, apply it to the named business, then explain the business impact, using Lego Harry Potter sets as the worked example."}'::jsonb),
('business:2-4-2-product-and-product-life:tips:7e65a8a9', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (7 marks) — Evaluating the Usefulness of the PLC", "reading": "<p>When evaluating if a business should use the PLC to plan marketing (like the Ford Motors 7-mark question), you must provide a balanced argument.</p>\n      <p><strong>Pro:</strong> Helps them know exactly when to spend money on advertising or when to reduce prices.</p>\n      <p><strong>Con:</strong> It ignores external factors. A competitor might release a revolutionary car, making Ford''s car enter ''decline'' years earlier than the graph predicted.</p>", "question": "In the balanced argument for evaluating whether a business like Ford should rely on the PLC to plan marketing, what is given as the main ''con''?", "options": ["It costs too much money to draw the graph", "It only works for service businesses, not manufacturers", "It ignores external factors, like a rival''s new product", "It cannot be used alongside extension strategies"]}'::jsonb, '{"answer": 2, "explain": "The exam tip''s ''Con'' point states the PLC ignores external factors, such as a competitor''s revolutionary car pushing a product into decline earlier than the graph predicted."}'::jsonb),
('business:2-4-2-product-and-product-life:fib:35233a5f', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'fib', 'fib', 2, '{"question": "The product life cycle is divided into _____ parts and shows the _____ of a product measured against time.", "blankOptions": {"B1": ["four", "profit", "growth", "replacement"], "B2": ["life", "invention", "maturity", "decline"]}}'::jsonb, '{"blanks": {"B1": "four", "B2": "life"}}'::jsonb),
('business:2-4-2-product-and-product-life:fib:83243b9f', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'fib', 'fib', 2, '{"question": "The first stage is called _____ and is where the product is new. Advertising is often _____ at this stage to make sure customers are aware of it.", "blankOptions": {"B1": ["slowing", "introduction", "four", "growth"], "B2": ["high", "profit", "maturity", "sales"]}}'::jsonb, '{"blanks": {"B1": "introduction", "B2": "high"}}'::jsonb),
('business:2-4-2-product-and-product-life:fib:0795ab7c', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'fib', 'fib', 2, '{"question": "The next stage is _____ where the product is becoming well-known and sales rise rapidly.", "blankOptions": {"B1": ["growth", "innovation", "high", "maturity"], "B2": ["replacement", "high", "sales", "profit"]}}'::jsonb, '{"blanks": {"B1": "growth", "B2": "sales"}}'::jsonb),
('business:2-4-2-product-and-product-life:fib:3b04675b', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'fib', 'fib', 2, '{"question": "When the product reaches _____, sales are at their highest, though sales growth is _____.", "blankOptions": {"B1": ["maturity", "life", "sales", "introduction"], "B2": ["slowing", "replacement", "growth", "life"]}}'::jsonb, '{"blanks": {"B1": "maturity", "B2": "slowing"}}'::jsonb),
('business:2-4-2-product-and-product-life:fib:f655ddc5', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'fib', 'fib', 2, '{"question": "The final stage is _____ where sales are falling and a business might be thinking of introducing a _____ product.", "blankOptions": {"B1": ["maturity", "four", "profit", "decline"], "B2": ["life", "four", "replacement", "profit"]}}'::jsonb, '{"blanks": {"B1": "decline", "B2": "replacement"}}'::jsonb),
('business:2-4-2-product-and-product-life:match:24b254f0', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Invention”?", "options": ["When a business comes up with a completely new product or service from scratch.", "Sales are falling; the product is seen as old and customers switch to replacements.", "The product is new, sales are just beginning, and advertising is high to build awareness.", "Sales grow quickly as the product becomes well-known; profits begin to rise."]}'::jsonb, '{"answer": 0, "explain": "“Invention” means: When a business comes up with a completely new product or service from scratch."}'::jsonb),
('business:2-4-2-product-and-product-life:match:d34ad843', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Innovation”?", "options": ["Methods used (like price drops or new packaging) to keep sales high during the maturity stage.", "Sales reach their peak and level off; growth slows down. High competition.", "When a business improves a product which already exists (e.g. adding Bluetooth to a toothbrush).", "When a business plans what a product will do (function) and what it will look like (style)."]}'::jsonb, '{"answer": 2, "explain": "“Innovation” means: When a business improves a product which already exists (e.g. adding Bluetooth to a toothbrush)."}'::jsonb),
('business:2-4-2-product-and-product-life:match:24216dae', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Design”?", "options": ["Sales are falling; the product is seen as old and customers switch to replacements.", "When a business plans what a product will do (function) and what it will look like (style).", "The product is new, sales are just beginning, and advertising is high to build awareness.", "When a business improves a product which already exists (e.g. adding Bluetooth to a toothbrush)."]}'::jsonb, '{"answer": 1, "explain": "“Design” means: When a business plans what a product will do (function) and what it will look like (style)."}'::jsonb),
('business:2-4-2-product-and-product-life:match:61b355af', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Introduction Stage”?", "options": ["Methods used (like price drops or new packaging) to keep sales high during the maturity stage.", "Sales are falling; the product is seen as old and customers switch to replacements.", "When a business plans what a product will do (function) and what it will look like (style).", "The product is new, sales are just beginning, and advertising is high to build awareness."]}'::jsonb, '{"answer": 3, "explain": "“Introduction Stage” means: The product is new, sales are just beginning, and advertising is high to build awareness."}'::jsonb),
('business:2-4-2-product-and-product-life:match:0780f56e', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Growth Stage”?", "options": ["Sales are falling; the product is seen as old and customers switch to replacements.", "Sales reach their peak and level off; growth slows down. High competition.", "Sales grow quickly as the product becomes well-known; profits begin to rise.", "Methods used (like price drops or new packaging) to keep sales high during the maturity stage."]}'::jsonb, '{"answer": 2, "explain": "“Growth Stage” means: Sales grow quickly as the product becomes well-known; profits begin to rise."}'::jsonb),
('business:2-4-2-product-and-product-life:match:fda29a17', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Maturity Stage”?", "options": ["When a business plans what a product will do (function) and what it will look like (style).", "Sales reach their peak and level off; growth slows down. High competition.", "Sales grow quickly as the product becomes well-known; profits begin to rise.", "Methods used (like price drops or new packaging) to keep sales high during the maturity stage."]}'::jsonb, '{"answer": 1, "explain": "“Maturity Stage” means: Sales reach their peak and level off; growth slows down. High competition."}'::jsonb),
('business:2-4-2-product-and-product-life:match:202015e3', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Decline Stage”?", "options": ["Sales are falling; the product is seen as old and customers switch to replacements.", "The product is new, sales are just beginning, and advertising is high to build awareness.", "When a business comes up with a completely new product or service from scratch.", "When a business plans what a product will do (function) and what it will look like (style)."]}'::jsonb, '{"answer": 0, "explain": "“Decline Stage” means: Sales are falling; the product is seen as old and customers switch to replacements."}'::jsonb),
('business:2-4-2-product-and-product-life:match:9eea5cfa', 'business', 'business:2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Extension Strategy”?", "options": ["The product is new, sales are just beginning, and advertising is high to build awareness.", "Sales grow quickly as the product becomes well-known; profits begin to rise.", "When a business improves a product which already exists (e.g. adding Bluetooth to a toothbrush).", "Methods used (like price drops or new packaging) to keep sales high during the maturity stage."]}'::jsonb, '{"answer": 3, "explain": "“Extension Strategy” means: Methods used (like price drops or new packaging) to keep sales high during the maturity stage."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:ef1be0fe', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Price skimming is best defined as:", "options": ["charging a lower price when a product becomes old", "keeping the price of a product the same as competitors", "making sure your price is always more than competitors permanently", "setting a higher price when a product is new and has an advantage over competitors"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: Skimming sets a high initial price for a new, highly desired or technical product, lowering it later when competitors enter."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:c4c2c117', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Penetration pricing would normally be used when:", "options": ["a business has been in operation some time and has few competitors", "a product is being introduced which is at the cutting edge of technology", "a business is new and needs to establish its place in a crowded market", "there is incredibly high demand for a luxury product"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Penetration pricing involves setting prices below competitors to ''break into'' a crowded market and steal market share quickly."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:b33ef750', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "If a business wishes to dispose of old stock to make way for new products, it would normally consider:", "options": ["Competitor pricing", "Promotional pricing", "Cost-plus pricing", "Skimming"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Promotional pricing (like a store sale) reduces prices for a short period specifically to clear old stock or give a quick boost to sales."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:aa6c4327', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A business is likely to use cost-plus pricing when it:", "options": ["has surplus stock to sell off quickly", "sees that a number of competitors are starting to have an effect on sales", "feels that it must guarantee a set amount of profit is made on every unit sold", "is a new business and has to make sure it has an advantage over competitors"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Cost-plus pricing calculates the exact cost to make the item and adds a specific percentage mark-up, guaranteeing that a profit is made on each sale."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:2d285bd4', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A hairdresser charges the exact same price for haircuts as two other hairdressers in the local area. Which pricing method is this?", "options": ["Competitor pricing", "Cost-plus pricing", "Penetration pricing", "Promotional pricing"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: By setting prices identically to local rivals, the business is using competitor pricing."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:cd535b89', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A fast-food restaurant is currently charging 60p for its new healthy snack. It intends to increase the price to £2.25 once the snack has become popular. This is an example of:", "options": ["Competitor pricing", "Cost-plus pricing", "Penetration pricing", "Price skimming"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Starting with an artificially low price to gain popularity and market share, with the intent to raise it later, is the exact definition of penetration pricing."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:645c7c78', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A store buys frozen oven chips for 29p a pack. The store usually sells them for 99p. If it wishes to use them as a ''loss leader'', how much should it charge?", "options": ["29p a pack", "Between 29p and 99p a pack", "Less than 29p a pack", "More than 99p a pack"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: A loss leader must be sold at a price lower than the cost it took the business to acquire or make it. Since the cost was 29p, a loss leader price must be less than 29p."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:e033a526', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Which of the following is a major disadvantage of Competitor Pricing?", "options": ["It guarantees a profit on every item sold.", "It results in massive cash flow problems immediately.", "The business must find other, non-price ways to attract customers.", "It makes the product look too cheap and damages brand image."]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Because the price is identical to rivals, the business loses price as a competitive advantage and must compete on quality, service, or advertising instead."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:83b04486', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Apple introduces its latest iPhone. What pricing strategy are they most likely to use?", "options": ["Penetration pricing", "Price Skimming", "Cost-plus pricing", "Promotional pricing"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Apple uses price skimming. Consumers want to be up-to-date with the latest technology and are willing to pay a very high premium price at launch."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:8e38d193', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "What is the primary danger of using Promotional Pricing too often?", "options": ["Customers may get used to the cheap prices and refuse to buy at full price.", "Competitors will immediately go bankrupt.", "The business will automatically gain a 100% market share.", "The cost of manufacturing the product will increase."]}'::jsonb, '{"answer": 0, "explain": "Correct answer: Frequent sales train customers to simply wait for the next sale rather than ever paying the full retail price, damaging long-term revenue."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:fd4d7b2c', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "Which pricing strategy is most likely to help a business recover high Research and Development (R&D) costs quickly?", "options": ["Penetration Pricing", "Price Skimming", "Loss Leader", "Competitor Pricing"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Price skimming generates high revenue margins immediately upon launch, which is crucial for tech or medical companies trying to pay back massive R&D investments."}'::jsonb),
('business:2-4-3-pricing-methods:mcq:f6e96419', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'mcq', 'mcq', 1, '{"question": "A new coach operator introduces a long-distance service. They charge £1 for tickets for the first month to establish the business. This is:", "options": ["Promotional pricing", "Price skimming", "Cost-plus pricing", "Premium pricing"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: (Note: It also has elements of penetration, but OCR mark schemes heavily accept Promotional Pricing for short-term massive discounts used to help a new service become established)."}'::jsonb),
('business:2-4-3-pricing-methods:tf:f851810e', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Cost-plus pricing guarantees that a business will always make an overall profit for the year."}'::jsonb, '{"answer": false, "explain": "FALSE. While it guarantees a profit margin on *each item sold*, the business will still make an overall loss if they do not sell enough items to cover their fixed costs."}'::jsonb),
('business:2-4-3-pricing-methods:tf:46a3a661', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Penetration pricing is a strategy that a business should use permanently."}'::jsonb, '{"answer": false, "explain": "FALSE. Penetration pricing should only last for a short period of time. Once the business has established market share, it must raise prices, otherwise it will suffer low profitability long-term."}'::jsonb),
('business:2-4-3-pricing-methods:tf:af16be0b', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Price skimming is most effective when a business introduces a highly innovative, technological product with no direct rivals."}'::jsonb, '{"answer": true, "explain": "TRUE. Skimming works best when early adopters are desperate for the newest tech and are willing to pay a premium before competitors have time to copy the product."}'::jsonb),
('business:2-4-3-pricing-methods:tf:9f31a72b', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "A disadvantage of competitor pricing is that the business has to spend money constantly researching what its rivals are charging."}'::jsonb, '{"answer": true, "explain": "TRUE. Competitor pricing requires constant monitoring of rival prices, which increases administrative costs."}'::jsonb),
('business:2-4-3-pricing-methods:tf:ba9e06a9', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "A loss leader is a product that is sold at exactly the price it costs to manufacture."}'::jsonb, '{"answer": false, "explain": "FALSE. A loss leader is sold *below* the cost to manufacture. The business deliberately takes a financial loss on that specific item to entice customers into the store."}'::jsonb),
('business:2-4-3-pricing-methods:tf:e375ed0d', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Using promotional pricing too often can damage a brand''s image for quality."}'::jsonb, '{"answer": true, "explain": "TRUE. If a brand is constantly ''on sale'', customers stop seeing it as a premium product and refuse to ever pay the full retail price."}'::jsonb),
('business:2-4-3-pricing-methods:tf:2ebcb963', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Cost-plus pricing takes competitor prices into account before setting the final price."}'::jsonb, '{"answer": false, "explain": "FALSE. One of the main disadvantages of cost-plus pricing is that it completely *ignores* external factors like competitor prices and what customers are willing to pay."}'::jsonb),
('business:2-4-3-pricing-methods:tf:533f734b', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Price skimming involves starting with a low price and gradually raising it."}'::jsonb, '{"answer": false, "explain": "FALSE. You are describing penetration pricing. Price skimming starts HIGH and drops LOW as the product ages."}'::jsonb),
('business:2-4-3-pricing-methods:tf:17353439', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "If a business uses competitor pricing, it must find a non-price way to stand out (like better service or packaging)."}'::jsonb, '{"answer": true, "explain": "TRUE. Because they cannot compete by being cheaper, they must differentiate their product in other ways."}'::jsonb),
('business:2-4-3-pricing-methods:tf:bebfccfc', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Penetration pricing builds brand loyalty because customers are attracted to try the product due to the low price."}'::jsonb, '{"answer": true, "explain": "TRUE. The low introductory price reduces the risk for customers to try an unknown brand. If the product is good, they develop loyalty and continue buying it even when the price rises."}'::jsonb),
('business:2-4-3-pricing-methods:tf:01119c7d', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "A major supermarket like Tesco doesn''t need to consider competitor pricing because it is so large."}'::jsonb, '{"answer": false, "explain": "FALSE. The ''Big Four'' supermarkets operate in a highly competitive market and constantly monitor each other''s prices, frequently offering price-matches to avoid losing customers."}'::jsonb),
('business:2-4-3-pricing-methods:tf:581764be', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'tf', 'tf', 1, '{"question": "Price is the only element of the marketing mix that directly generates revenue."}'::jsonb, '{"answer": true, "explain": "TRUE. Product, Place, and Promotion all involve spending money (costs). Price dictates the money coming into the business."}'::jsonb),
('business:2-4-3-pricing-methods:learn:753da832', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "The Importance of Price", "reading": "<p>A business must take great care when deciding what price to charge for a product or service. Price is the only part of the marketing mix that directly generates <strong>revenue</strong>.</p>\n      <p>Most consumers take notice of the price. If a business sets a price too high, sales will fall. If it sets a price too low, it will not make the profits needed for investment and to reward shareholders. The price must also be consistent with the other 3 Ps (Product, Place, Promotion) as it affects the consumer''s perception of the good or service.</p>\n      <p><strong>Main factors that influence pricing decisions:</strong></p>\n      <ul>\n      <li>Costs (a business must cover its costs to survive)</li>\n      <li>Competitors'' prices</li>\n      <li>The Product Life Cycle (prices change as products age)</li>\n      <li>Market Share objectives</li>\n      <li>Positioning and Brand Image</li>\n      </ul>", "question": "Which part of the marketing mix is the only one that directly generates revenue for a business?", "options": ["Price", "Promotion", "Place", "Product"]}'::jsonb, '{"answer": 0, "explain": "Price is the only element of the 4Ps that directly brings money into the business; Product, Place and Promotion all involve costs."}'::jsonb),
('business:2-4-3-pricing-methods:learn:fe5baa30', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "Cost-Plus Pricing", "reading": "<p><strong>Cost-plus pricing</strong> is a method where the business looks at the total cost of manufacturing a product and then adds a percentage of profit (the ''mark-up'' or ''plus'' part) to arrive at the selling price.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">A profit is guaranteed on each item sold (providing enough items are sold).</div>\n      <div class=\"pro-item\">It is a relatively simple and easy way to set a price.</div>\n      <div class=\"pro-item\">Owners are in full control of the profit margin achieved.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">Ignores external factors like competitor prices or customers'' willingness to pay.</div>\n      <div class=\"con-item\">If the mark-up is set too high, the price may be expensive compared to rivals, leading to lost sales.</div>\n      <div class=\"con-item\">If costs fluctuate frequently, the selling price may have to continually change.</div>\n      </div>\n      </div>", "question": "What is the main disadvantage of cost-plus pricing?", "options": ["It cannot be calculated by small businesses", "It ignores competitor prices and what customers will pay", "It always results in lower profit margins than skimming", "It never guarantees a profit on items sold"]}'::jsonb, '{"answer": 1, "explain": "Cost-plus pricing only considers internal costs plus a mark-up, so it ignores external factors such as competitors'' prices."}'::jsonb),
('business:2-4-3-pricing-methods:learn:9e592975', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "Competitor Pricing", "reading": "<p><strong>Competitor pricing</strong> (or competitive pricing) is used when there is a lot of competition selling the same or similar products. A business will look at what other competitors charge and charge the same (or very slightly less).</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Selling prices are in line with rivals, so it should attract customers and prevent them from switching brands.</div>\n      <div class=\"pro-item\">Helps a business survive in a highly crowded and established market.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">Because price is the same as rivals, the business must find other (often expensive) ways to attract customers, like better customer service or more promotion.</div>\n      <div class=\"con-item\">The business must constantly research competitors'' prices, which increases administrative costs.</div>\n      </div>\n      </div>", "question": "A major disadvantage of competitor pricing is that a business...", "options": ["must always price below all rivals", "must find other costly ways to attract customers", "will automatically dominate the market", "can no longer make any profit on its products"]}'::jsonb, '{"answer": 1, "explain": "Because the price matches rivals, the business must compete on non-price factors like customer service or promotion, as the card''s disadvantages note."}'::jsonb),
('business:2-4-3-pricing-methods:learn:3d31f9f9', 'business', 'business:2-4-3-pricing-methods', '2.4.3 Pricing Methods', 'learn', 'mcq', 1, '{"readingTitle": "Penetration Pricing", "reading": "<p><strong>Penetration pricing</strong> is used when a business is new to a crowded market. They price their products <em>below</em> that of competitors to ''penetrate'' or break into the market and tempt consumers away from established brands. Once established, the price is raised. It is a short-term strategy.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Cash flow and market share improve quickly as sales increase rapidly.</div>\n      <div class=\"pro-item\">Can lead to loyal customers who trial the product because of the low price and stick with it.</div>\n      <div class=\"pro-item\">Helps develop long-term profitability through higher market share.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">In the short term, it is likely to result in lower profits (or even a loss) compared to if prices were higher.</div>\n      <div class=\"con-item\">It can be difficult to raise the selling price in the future without upsetting customers.</div>\n      </div>\n      </div>", "question": "Penetration pricing involves setting a price that is...", "options": ["above competitors to signal premium quality", "below rivals to enter a crowded market, then raised", "below cost permanently to eliminate all rivals", "identical to competitors to avoid losing customers"]}'::jsonb, '{"answer": 1, "explain": "Penetration pricing means pricing below rivals to ''penetrate'' a crowded market, with the price raised once the business is established."}'::jsonb)
